#include<bits/stdc++.h>
using namespace std;
int a[401],cnt[11],dp[41][41][41][41];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<=m;i++)
    {
        int x;
        scanf("%d",&x);
        cnt[x]++;
    }
    dp[0][0][0][0]=a[1];
    for(int i=0;i<=cnt[1];i++)
    {
        for(int j=0;j<=cnt[2];j++)
        {
            for(int k=0;k<=cnt[3];k++)
            {
                for(int l=0;l<=cnt[4];l++)
                {
                    int tmp=1+i+j*2+k*3+l*4;
                    if(i)
                    {
                        dp[i][j][k][l]=max(dp[i][j][k][l],dp[i-1][j][k][l]+a[tmp]);
                    }
                    if(j)
                    {
                        dp[i][j][k][l]=max(dp[i][j][k][l],dp[i][j-1][k][l]+a[tmp]);
                    }
                    if(k)
                    {
                        dp[i][j][k][l]=max(dp[i][j][k][l],dp[i][j][k-1][l]+a[tmp]);
                    }
                    if(l)
                    {
                        dp[i][j][k][l]=max(dp[i][j][k][l],dp[i][j][k][l-1]+a[tmp]);
                    }
                }
            }
        }
    }
    printf("%d",dp[cnt[1]][cnt[2]][cnt[3]][cnt[4]]);
    return 0;
}
